def train_and_save():
    from sklearn.ensemble import RandomForestClassifier
    from sklearn.preprocessing import LabelEncoder, StandardScaler
    from sklearn.model_selection import cross_val_score

    np.random.seed(42)
    X_list, y_list = [], []

    for crop, stats in REAL_CROP_STATS.items():
        n = 120
        def sample(key):
            mean, std, mn, mx = stats[key]
            return np.clip(np.random.normal(mean, std, n), mn, mx)

        N    = sample('N')
        P    = sample('P')
        K    = sample('K')
        temp = sample('temp')
        hum  = sample('hum')
        ph   = sample('ph')
        rain = sample('rain')

        # Feature engineering — add derived ratios that help distinguish crops
        NP_ratio = np.clip(N / (P + 1), 0, 20)
        KN_ratio = np.clip(K / (N + 1), 0, 10)
        rain_hum  = rain * hum / 100

        X_list.append(np.column_stack([
            N, P, K, temp, hum, ph, rain,
            NP_ratio, KN_ratio, rain_hum
        ]))
        y_list.extend([crop] * n)

    X = np.vstack(X_list)
    y = np.array(y_list)

    le = LabelEncoder()
    y_enc = le.fit_transform(y)

    scaler = StandardScaler()
    X_scaled = scaler.fit_transform(X)

    # Optimised Random Forest with balanced classes and feature engineering
    model = RandomForestClassifier(
        n_estimators=250, max_depth=16,
        min_samples_split=3, min_samples_leaf=1,
        max_features='sqrt', class_weight='balanced',
        random_state=42, n_jobs=-1
    )
    model.fit(X_scaled, y_enc)

    scores = cross_val_score(model, X_scaled, y_enc, cv=5, scoring='accuracy', n_jobs=-1)
    print(f"Cross-validation accuracy: {scores.mean()*100:.1f}% +/- {scores.std()*100:.1f}%")

    model_dir = os.path.dirname(os.path.abspath(__file__))
    with open(os.path.join(model_dir, 'crop_model.pkl'),    'wb') as f: pickle.dump(model,  f)
    with open(os.path.join(model_dir, 'label_encoder.pkl'), 'wb') as f: pickle.dump(le,     f)
    with open(os.path.join(model_dir, 'scaler.pkl'),        'wb') as f: pickle.dump(scaler, f)

    print(f"Model: {len(REAL_CROP_STATS)} crops x 150 samples = {len(X)} points, {X.shape[1]} features")
    print(f"Crops trained: {len(le.classes_)}")
    return model, le, scaler


if __name__ == '__main__':
    train_and_save()